                            <path
                                d="M8 4v12M16 8v8M4 8h4M12 16h4M4 16h2M18 8h2M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"
                                stroke="currentColor" stroke-linecap="round" />
